import React, { Component } from 'react';
import './utilities.css';
import 'bootstrap/dist/css/bootstrap.min.css';
class App extends Component {
  render() {
    return (
      <div className="App">
        <MyNavBar />
        <div id="home">
          <Home />
        </div>
        <div id="projects">
          <Spring />
        </div>
        <div id="about">
          <About />
        </div>

      </div>
    );
  }

}

export default App;
